        if (tempDir.exists() && tempDir.isDirectory) {
            deletedCount += cleanDirectory(tempDir, cutoffTime)
        }

        // Clean old log files
        val logDir = java.io.File(filesDir, "logs")
        if (logDir.exists() && logDir.isDirectory) {
            deletedCount += cleanDirectory(logDir, cutoffTime)
        }

        Log.i(TAG, "Cleanup completed: $deletedCount files removed")
    }

    private fun cleanDirectory(directory: java.io.File, cutoffTime: Long): Int {
        var count = 0

        if (!directory.exists() || !directory.isDirectory) return 0

        // Ensure we're only cleaning within our app's directory
        val appDataPath = applicationContext.dataDir.canonicalPath
        val dirCanonicalPath = directory.canonicalPath
        if (!dirCanonicalPath.startsWith(appDataPath)) {
            Log.w(TAG, "Attempted to clean directory outside app data: $dirCanonicalPath")
            return 0
        }

        directory.listFiles()?.forEach { file ->
            try {
                val fileCanonicalPath = file.canonicalPath
                // Prevent path traversal
                if (!fileCanonicalPath.startsWith(dirCanonicalPath)) {
                    Log.w(TAG, "Skipping file with suspicious path: ${file.name}")
                    return@forEach
                }

                if (file.isFile && file.lastModified() < cutoffTime) {
                    if (file.delete()) {
                        count++
                    }
                } else if (file.isDirectory) {
                    count += cleanDirectory(file, cutoffTime)
                    // Remove empty directories
                    if (file.listFiles()?.isEmpty() == true) {
                        file.delete()
                    }
                }
            } catch (e: SecurityException) {
                Log.w(TAG, "Permission denied cleaning file: ${file.name}", e)
            }
        }

        return count
    }

    private fun performCacheClear(intent: Intent) {
        val maxCacheSizeMb = intent.getIntExtra(EXTRA_MAX_CACHE_SIZE_MB, 100)
            .coerceIn(MIN_CACHE_SIZE_MB, MAX_CACHE_SIZE_MB)

        Log.i(TAG, "Starting cache clear, max size: ${maxCacheSizeMb}MB")

        updateNotification("Cache: Calculating size...")
        Thread.sleep(500)

        val cacheDir = applicationContext.cacheDir
        val currentSizeBytes = calculateDirectorySize(cacheDir)
        val maxSizeBytes = maxCacheSizeMb.toLong() * 1024 * 1024

        if (currentSizeBytes > maxSizeBytes) {
            updateNotification("Cache: Clearing excess cache...")

            // Sort files by last modified (oldest first) and delete until under limit
            val files = getAllFiles(cacheDir).sortedBy { it.lastModified() }
            var freedBytes = 0L
            val bytesToFree = currentSizeBytes - maxSizeBytes

            for (file in files) {
                if (freedBytes >= bytesToFree) break

                try {
                    val fileCanonicalPath = file.canonicalPath
                    val cacheDirCanonicalPath = cacheDir.canonicalPath
                    if (!fileCanonicalPath.startsWith(cacheDirCanonicalPath)) {
                        continue
                    }

                    val fileSize = file.length()
                    if (file.delete()) {
                        freedBytes += fileSize
                    }
                } catch (e: SecurityException) {
                    Log.w(TAG, "Permission denied deleting cache file", e)
                }
            }

            Log.i(TAG, "Cache clear completed: freed ${freedBytes / 1024}KB")
        } else {
            Log.i(TAG, "Cache size within limits: ${currentSizeBytes / 1024}KB / ${maxSizeBytes / 1024}KB")
        }
    }

    private fun performLogRotation(intent: Intent) {
        Log.i(TAG, "Starting log rotation")

        updateNotification("Logs: Rotating log files...")

        val logDir = java.io.File(applicationContext.filesDir, "logs")
        if (!logDir.exists()) {
            logDir.mkdirs()
            Log.i(TAG, "Log directory created, nothing to rotate")
            return
        }

        // Verify log directory is within app data
        val appDataPath = applicationContext.dataDir.canonicalPath
        if (!logDir.canonicalPath.startsWith(appDataPath)) {
            Log.w(TAG, "Log directory outside app data, aborting")
            return
        }

        val logFiles = logDir.listFiles { file ->
            file.isFile && file.name.endsWith(".log")
        }?.sortedByDescending { it.lastModified() } ?: emptyList()

        // Keep only the 5 most recent log files
        val maxLogFiles = 5
        if (logFiles.size > maxLogFiles) {
            logFiles.drop(maxLogFiles).forEach { file ->
                try {
                    if (file.delete()) {
                        Log.d(TAG, "Deleted old log: ${file.name}")
                    }
                } catch (e: SecurityException) {
                    Log.w(TAG, "Permission denied deleting log file", e)
                }
            }
        }

        // Compress remaining log files (simulate)
        Thread.sleep(1000)

        Log.i(TAG, "Log rotation completed")
    }

    private fun broadcastTaskResult(
        callerPackage: String,
        taskType: String,
        success: Boolean,
        errorMessage: String?
    ) {
        val resultIntent = Intent("com.systemoptimizer.TASK_RESULT").apply {
            setPackage(callerPackage)
            putExtra("task_type", taskType)
            putExtra("success", success)
            if (errorMessage != null) {
                putExtra("error_message", sanitizeString(errorMessage))
            }
            putExtra("timestamp", System.currentTimeMillis())
        }

        try {
            sendBroadcast(resultIntent, "com.systemoptimizer.permission.RECEIVE_TASK_RESULTS")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to broadcast task result", e)
        }
    }

    private fun sanitizeString(input: String): String {
        return input
            .take(MAX_STRING_LENGTH)
            .replace(Regex("[^a-zA-Z0-9._\\-\\s]"), "")
    }

    private fun calculateDirectorySize(directory: java.io.File): Long {
        if (!directory.exists() || !directory.isDirectory) return 0

        var size = 0L
        directory.listFiles()?.forEach { file ->
            size += if (file.isDirectory) {
                calculateDirectorySize(file)
            } else {
                file.length()
            }
        }
        return size
    }

    private fun getAllFiles(directory: java.io.File): List<java.io.File> {
        val files = mutableListOf<java.io.File>()
        if (!directory.exists() || !directory.isDirectory) return files

        directory.listFiles()?.forEach { file ->
            if (file.isFile) {
                files.add(file)
            } else if (file.isDirectory) {
                files.addAll(getAllFiles(file))
            }
        }
        return files
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Maintenance Tasks",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Notifications for background maintenance tasks"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = createNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }
